interface.signature:
t(key: string, options?: I18nTranslateOptions): string

interface I18nTranslateOptions {
  lang?: string;              // Override language
  args?: Record; // Variable replacement {{key}}
  defaultValue?: string;      // Fallback if key not found
}

// Usage examples:
this.i18n.t('auth.LOGIN_SUCCESS')
// => "Login successful"

this.i18n.t('auth.OTP_SENT', { args: { phone: '+905551234567' } })
// => "OTP sent to +905551234567"

this.i18n.t('users.NOT_FOUND', { lang: 'tr' })
// => "Kullanıcı bulunamadı"

I18nModule.forRoot({
  fallbackLanguage: 'en',
  loaderOptions: {
    path: path.join(__dirname, '/modules/i18n/translations/'),
    watch: true,
  },
  resolvers: [
    AcceptLanguageResolver,
  ],
})

// common.json
{
  "SUCCESS": "Operation successful",
  "ERROR": "An error occurred",
  "NOT_FOUND": "Resource not found",
  "UNAUTHORIZED": "Unauthorized access",
  "FORBIDDEN": "Access forbidden",
  "VALIDATION_ERROR": "Validation failed",
  "INTERNAL_ERROR": "Internal server error"
}

// auth.json
{
  "LOGIN_SUCCESS": "Login successful",
  "LOGIN_FAILED": "Invalid credentials",
  "LOGOUT_SUCCESS": "Logout successful",
  "TOKEN_EXPIRED": "Token has expired",
  "TOKEN_INVALID": "Invalid token",
  "OTP_SENT": "OTP sent to {{phone}}",
  "OTP_INVALID": "Invalid OTP code",
  "PASSWORD_RESET_SUCCESS": "Password reset successful"
}

// users.json
{
  "USER_CREATED": "User created successfully",
  "USER_UPDATED": "User updated successfully",
  "USER_DELETED": "User deleted successfully",
  "USER_NOT_FOUND": "User not found",
  "INVALID_CREDENTIALS": "Invalid credentials"
}

// Before (hardcoded):
throw new NotFoundException('User not found');

// After (i18n):
throw new NotFoundException(this.i18n.t('users.NOT_FOUND'));

// With variables:
throw new BadRequestException(
  this.i18n.t('auth.OTP_SENT', { args: { phone: user.phoneNumber } })
);
